public String zipZap(String str)
{
    if(str.length() < 3) {
        return str;
    }

    StringBuilder result = new StringBuilder();

    for(int i = 0; i < str.length(); i++) {
        if(i + 2 < str.length() && str.charAt(i) == 'z' && str.charAt(i + 2) == 'p') {
            result.append("zp");
            i += 2;
        } else {
            result.append(str.charAt(i));
        }
    }

    return result.toString();
}

